摘要：本文介绍了如何使用StAX解析XML文档。 环境 Windows 10 企业版 LTSC 21H2Java 1.8 1 定义StAX（Streaming API for XML）是一种基于流式处理的XML解析API。StAX采用拉模式解析数据，允许应用程序主动控制解析过程，在需要时获取下一个解析事件。 2 基本原理StAX解析器的核心工作流程： 创建解析器：通过XMLInputFactory工厂创建XMLStreamReader实例或XMLEventReader实例。 主动拉取：应用程序主动调用获取下一个解析事件。 处理事件：根据事件类型进行相应的数据处理。 状态控制：应用程序完全控制解析进度，可以随时停止或跳过内容。 关键特性： 拉模式解析：应用程序控制解析流程。 双向访问：支持读取和写入。 内存高效：不需要将整个文档加载到内存。 灵活性高：可以随时停止或跳过内容。 StAX提供两种编程模型： 基于指针的模型（XMLStreamReader）通过next()方法获取事件，进而获取事件类型和具体内容，性能更高，使用更底层。 基于迭代器的模型（XMLEventReader）通过nextEvent()方法获取事件对象，进而获取事件信息，更面向对象，使用更简单。 3 文档示例以一个简单的XML文档为例： school.xml12345678910111213141516171819202122232425262728293031323334&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;school address=&quot;北京市海淀区&quot;&gt; &lt;name&gt;阳光小学&lt;/name&gt; &lt;teachers&gt; &lt;teacher id=&quot;teacher_1&quot;&gt; &lt;name&gt;李明&lt;/name&gt; &lt;subject&gt;语文&lt;/subject&gt; &lt;/teacher&gt; &lt;teacher id=&quot;teacher_2&quot;&gt; &lt;name&gt;赵强&lt;/name&gt; &lt;subject&gt;数学&lt;/subject&gt; &lt;/teacher&gt; &lt;/teachers&gt; &lt;students&gt; &lt;student id=&quot;student_1&quot;&gt; &lt;name&gt;张婷&lt;/name&gt; &lt;gender&gt;女&lt;/gender&gt; &lt;age&gt;13&lt;/age&gt; &lt;hobbies&gt; &lt;hobby&gt;画画&lt;/hobby&gt; &lt;hobby&gt;弹琴&lt;/hobby&gt; &lt;/hobbies&gt; &lt;/student&gt; &lt;student id=&quot;student_2&quot;&gt; &lt;name&gt;王浩&lt;/name&gt; &lt;gender&gt;男&lt;/gender&gt; &lt;age&gt;14&lt;/age&gt; &lt;hobbies&gt; &lt;hobby&gt;跑步&lt;/hobby&gt; &lt;hobby&gt;游泳&lt;/hobby&gt; &lt;/hobbies&gt; &lt;/student&gt; &lt;/students&gt;&lt;/school&gt; 4 核心组件4.1 工厂类4.1.1 XMLInputFactory常用方法： java123456789101112// 获取工厂实例public static XMLInputFactory newInstance();// 创建XMLStreamReader实例public abstract XMLStreamReader createXMLStreamReader(InputStream stream);public abstract XMLStreamReader createXMLStreamReader(Reader reader);// 创建XMLEventReader实例public abstract XMLEventReader createXMLEventReader(InputStream stream);public abstract XMLEventReader createXMLEventReader(Reader reader);// 获取属性public abstract Object getProperty(String name);// 设置属性public abstract void setProperty(String name, Object value); 4.1.2 XMLOutputFactory常用方法： java12345// 获取工厂实例public static XMLOutputFactory newInstance();// 创建XMLStreamWriter实例public XMLStreamWriter createXMLStreamWriter(OutputStream stream);public XMLStreamWriter createXMLStreamWriter(Writer writer); 4.2 读取器类4.2.1 XMLStreamReader常用方法： java123456789101112131415161718192021222324// 移动到下一个事件public int next();// 判断是否还有事件public boolean hasNext();// 获取当前事件类型public int getEventType();// 获取元素限定名public QName getName();// 获取元素本地名public String getLocalName();// 获取元素文本内容public String getText();// 获取属性数量public int getAttributeCount();// 获取属性限定名public QName getAttributeName(int index);// 获取属性本地名public String getAttributeLocalName(int index);// 获取属性值public String getAttributeValue(int index);// 获取命名空间数量public int getNamespaceCount();// 获取命名空间URIpublic String getNamespaceURI(int index); 事件类型常量： java12345678910// 开始元素XMLStreamReader.START_ELEMENT// 结束元素XMLStreamReader.END_ELEMENT// 字符数据XMLStreamReader.CHARACTERS// 开始文档XMLStreamReader.START_DOCUMENT// 结束文档XMLStreamReader.END_DOCUMENT 4.2.2 XMLEventReader常用方法： java123456// 获取下一个事件public XMLEvent nextEvent();// 判断是否还有事件public boolean hasNext();// 预览下一个事件但不移动指针public XMLEvent peek(); 4.2.3 XMLEvent常用方法： java123456789101112// 获取事件类型public int getEventType();// 是否开始处理元素事件public boolean isStartElement();// 是否结束处理元素事件public boolean isEndElement();// 是否处理文本事件public boolean isCharacters();// 是否开始处理文档事件public boolean isStartDocument();// 是否结束处理文档事件public boolean isEndDocument(); 4.3 写入器类4.3.1 XMLStreamWriter常用方法： java12345678910111213141516// 写入文档开始public void writeStartDocument();// 写入文档结束public void writeEndDocument();// 写入开始元素public void writeStartElement(String localName);// 写入结束元素public void writeEndElement();// 写入空元素public void writeEmptyElement(String localName);// 写入文本public void writeCharacters(String text);// 写入属性public void writeAttribute(String localName, String value);// 写入命名空间public void writeNamespace(String prefix, String namespaceURI); 5 实际应用5.1 基础使用5.1.1 使用XMLStreamReader解析创建解析器并解析文档： java123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384public List&lt;Student&gt; parseWithStreamReader(String filePath) &#123; List&lt;Student&gt; students = new ArrayList&lt;&gt;(); XMLStreamReader reader = null; try &#123; // 创建XMLInputFactory对象 XMLInputFactory factory = XMLInputFactory.newInstance(); // 创建XMLStreamReader对象 reader = factory.createXMLStreamReader(new FileInputStream(filePath)); // 记录当前元素和文本 Student currentStudent = null; String currentElement = null; StringBuilder currentText = new StringBuilder(); // 处理文档开始事件 if (reader.getEventType() == XMLStreamReader.START_DOCUMENT) &#123; System.out.println(&quot;解析文档开始&quot;); &#125; // 遍历读取事件 while (reader.hasNext()) &#123; int eventType = reader.next(); switch (eventType) &#123; // 处理元素开始事件 case XMLStreamReader.START_ELEMENT: currentElement = reader.getLocalName(); if (&quot;student&quot;.equals(currentElement)) &#123; currentStudent = new Student(); // 处理属性 String id = reader.getAttributeValue(null, &quot;id&quot;); currentStudent.setId(id); &#125; break; // 处理文本事件 case XMLStreamReader.CHARACTERS: if (!reader.isWhiteSpace()) &#123; currentText.append(reader.getText()); &#125; break; // 处理元素结束事件 case XMLStreamReader.END_ELEMENT: String elementName = reader.getLocalName(); String text = currentText.toString().trim(); if (currentStudent != null) &#123; switch (elementName) &#123; case &quot;name&quot;: currentStudent.setName(text); break; case &quot;gender&quot;: currentStudent.setGender(text); break; case &quot;age&quot;: if (!text.isEmpty()) &#123; currentStudent.setAge(Integer.parseInt(text)); &#125; break; case &quot;hobby&quot;: currentStudent.addHobby(text); break; case &quot;student&quot;: students.add(currentStudent); currentStudent = null; break; &#125; &#125; currentText.setLength(0); break; &#125; &#125; // 处理文档结束事件 if (reader.getEventType() == XMLStreamReader.END_DOCUMENT) &#123; System.out.println(&quot;解析文档结束&quot;); &#125; &#125; catch (Exception e) &#123; e.printStackTrace(); return Collections.emptyList(); &#125; finally &#123; if (reader != null) &#123; try &#123; reader.close(); &#125; catch (XMLStreamException e) &#123; e.printStackTrace(); &#125; &#125; &#125; return students;&#125; 主方法： java12345public static void main(String[] args) &#123; StAX stax = new StAX(); List&lt;Student&gt; students = stax.parseWithStreamReader(&quot;src/main/resources/school.xml&quot;); students.forEach(System.out::println);&#125; 5.1.2 使用XMLEventReader解析创建解析器并解析文档： java123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081public List&lt;Student&gt; parseWithEventReader(String filePath) &#123; List&lt;Student&gt; students = new ArrayList&lt;&gt;(); XMLEventReader reader = null; try &#123; // 创建XMLInputFactory对象 XMLInputFactory factory = XMLInputFactory.newInstance(); // 创建XMLEventReader对象 reader = factory.createXMLEventReader(new FileInputStream(filePath)); // 记录当前元素和文本 Student currentStudent = null; String currentElement = null; // 遍历读取事件 while (reader.hasNext()) &#123; XMLEvent event = reader.nextEvent(); // 处理文档开始事件 if (event.isStartDocument()) &#123; System.out.println(&quot;解析文档开始&quot;); &#125; // 处理元素开始事件 if (event.isStartElement()) &#123; StartElement startElement = event.asStartElement(); currentElement = startElement.getName().getLocalPart(); if (&quot;student&quot;.equals(currentElement)) &#123; currentStudent = new Student(); // 处理属性 Attribute idAttr = startElement.getAttributeByName(new QName(&quot;id&quot;)); if (idAttr != null) &#123; currentStudent.setId(idAttr.getValue()); &#125; &#125; &#125; // 处理文本事件 if (event.isCharacters()) &#123; Characters characters = event.asCharacters(); String text = characters.getData().trim(); if (!text.isEmpty() &amp;&amp; currentStudent != null) &#123; switch (currentElement) &#123; case &quot;name&quot;: currentStudent.setName(text); break; case &quot;gender&quot;: currentStudent.setGender(text); break; case &quot;age&quot;: currentStudent.setAge(Integer.parseInt(text)); break; case &quot;hobby&quot;: currentStudent.addHobby(text); break; &#125; &#125; &#125; // 处理元素结束事件 if (event.isEndElement()) &#123; EndElement endElement = event.asEndElement(); String elementName = endElement.getName().getLocalPart(); if (&quot;student&quot;.equals(elementName)) &#123; students.add(currentStudent); currentStudent = null; &#125; currentElement = null; &#125; // 处理文档结束事件 if (event.isEndDocument()) &#123; System.out.println(&quot;解析文档结束&quot;); &#125; &#125; &#125; catch (Exception e) &#123; e.printStackTrace(); return Collections.emptyList(); &#125; finally &#123; if (reader != null) &#123; try &#123; reader.close(); &#125; catch (XMLStreamException e) &#123; e.printStackTrace(); &#125; &#125; &#125; return students;&#125; 主方法： java12345public static void main(String[] args) &#123; StAX stax = new StAX(); List&lt;Student&gt; students = stax.parseWithEventReader(&quot;src/main/resources/school.xml&quot;); students.forEach(System.out::println);&#125; 5.1.3 使用XMLStreamWriter写入写入文档： java12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970public void writeWithStreamWriter(List&lt;Student&gt; students, String filePath) &#123; XMLStreamWriter writer = null; try &#123; // 创建XMLOutputFactory对象 XMLOutputFactory factory = XMLOutputFactory.newInstance(); // 创建XMLStreamWriter对象 writer = factory.createXMLStreamWriter(new FileOutputStream(filePath), &quot;UTF-8&quot;); // 写入声明开始 writer.writeStartDocument(&quot;UTF-8&quot;, &quot;1.0&quot;); writer.writeCharacters(&quot;
&quot;); // 写入学校开始 writer.writeStartElement(&quot;school&quot;); writer.writeAttribute(&quot;address&quot;, &quot;北京市海淀区&quot;); writer.writeCharacters(&quot;
 &quot;); // 写入学校名称 writer.writeStartElement(&quot;name&quot;); writer.writeCharacters(&quot;阳光小学&quot;); writer.writeEndElement(); writer.writeCharacters(&quot;
 &quot;); // 写入学生列表开始 writer.writeStartElement(&quot;students&quot;); writer.writeCharacters(&quot;
&quot;); // 写入每个学生信息 for (Student student : students) &#123; // 写入学生开始 writer.writeCharacters(&quot; &quot;); writer.writeStartElement(&quot;student&quot;); writer.writeAttribute(&quot;id&quot;, student.getId()); writer.writeCharacters(&quot;
&quot;); // 写入学生信息 writeElement(writer, &quot;name&quot;, student.getName(), &quot; &quot;); writeElement(writer, &quot;gender&quot;, student.getGender(), &quot; &quot;); writeElement(writer, &quot;age&quot;, String.valueOf(student.getAge()), &quot; &quot;); // 写入学生爱好开始 writer.writeCharacters(&quot; &quot;); writer.writeStartElement(&quot;hobbies&quot;); writer.writeCharacters(&quot;
&quot;); for (String hobby : student.getHobbies()) &#123; // 写入学生爱好 writeElement(writer, &quot;hobby&quot;, hobby, &quot; &quot;); &#125; // 写入学生爱好结束 writer.writeCharacters(&quot; &quot;); writer.writeEndElement(); writer.writeCharacters(&quot;
&quot;); // 写入学生结束 writer.writeCharacters(&quot; &quot;); writer.writeEndElement(); writer.writeCharacters(&quot;
&quot;); &#125; // 写入学生列表结束 writer.writeCharacters(&quot; &quot;); writer.writeEndElement(); writer.writeCharacters(&quot;
&quot;); // 写入学校结束 writer.writeEndElement(); // 写入声明结束 writer.writeEndDocument(); &#125; catch (Exception e) &#123; e.printStackTrace(); &#125; finally &#123; if (writer != null) &#123; try &#123; writer.close(); &#125; catch (XMLStreamException e) &#123; e.printStackTrace(); &#125; &#125; &#125;&#125; 创建元素： java1234567private void writeElement(XMLStreamWriter writer, String elementName, String value, String indent) throws XMLStreamException &#123; writer.writeCharacters(indent); writer.writeStartElement(elementName); writer.writeCharacters(value); writer.writeEndElement(); writer.writeCharacters(&quot;
&quot;);&#125; 主方法： java123456789101112public static void main(String[] args) &#123; Student student = new Student(); student.setId(&quot;1&quot;); student.setName(&quot;小王&quot;); student.setGender(&quot;男&quot;); student.setAge(18); student.addHobby(&quot;唱歌&quot;); List&lt;Student&gt; students = new ArrayList&lt;&gt;(); students.add(student); StAX stax = new StAX(); stax.writeWithStreamWriter(students, &quot;src/main/resources/school-stax.xml&quot;);&#125; 5.2 高级特性5.2.1 流式处理文件批量处理文件信息： java12345678910111213141516171819202122232425262728293031323334public void processStudentList(String filePath) &#123; XMLStreamReader reader = null; try &#123; // 创建XMLInputFactory对象 XMLInputFactory factory = XMLInputFactory.newInstance(); // 创建XMLStreamReader对象 reader = factory.createXMLStreamReader(new FileInputStream(filePath)); // 每处理100个学生输出一次进度 int studentCount = 0; int batchSize = 100; // 遍历读取事件 while (reader.hasNext()) &#123; int eventType = reader.next(); if (eventType == XMLStreamReader.START_ELEMENT) &#123; if (&quot;student&quot;.equals(reader.getLocalName())) &#123; if (studentCount % batchSize == 0) &#123; System.out.println(&quot;已处理 &quot; + studentCount + &quot; 个学生&quot;); // 执行批量保存等操作 &#125; &#125; &#125; &#125; System.out.println(&quot;总共处理 &quot; + studentCount + &quot; 个学生&quot;); &#125; catch (Exception e) &#123; e.printStackTrace(); &#125; finally &#123; if (reader != null) &#123; try &#123; reader.close(); &#125; catch (XMLStreamException e) &#123; e.printStackTrace(); &#125; &#125; &#125; 5.2.2 使用命名空间使用命名空间： java1234567891011121314151617181920212223242526272829303132333435363738public void parseWithNamespaces(String filePath) &#123; XMLStreamReader reader = null; try &#123; // 创建XMLInputFactory对象 XMLInputFactory factory = XMLInputFactory.newInstance(); // 设置命名空间支持 factory.setProperty(XMLInputFactory.IS_NAMESPACE_AWARE, true); // 创建XMLStreamReader对象 reader = factory.createXMLStreamReader(new FileInputStream(filePath)); // 遍历读取事件 while (reader.hasNext()) &#123; int eventType = reader.next(); if (eventType == XMLStreamReader.START_ELEMENT) &#123; String localName = reader.getLocalName(); String namespaceURI = reader.getNamespaceURI(); String prefix = reader.getPrefix(); System.out.println(&quot;元素: &quot; + localName + &quot;, 命名空间: &quot; + namespaceURI + &quot;, 前缀: &quot; + prefix); // 处理命名空间声明 int namespaceCount = reader.getNamespaceCount(); for (int i = 0; i &lt; namespaceCount; i++) &#123; String nsPrefix = reader.getNamespacePrefix(i); String nsURI = reader.getNamespaceURI(i); System.out.println(&quot;命名空间声明: &quot; + nsPrefix + &quot;=&quot; + nsURI); &#125; &#125; &#125; &#125; catch (Exception e) &#123; e.printStackTrace(); &#125; finally &#123; if (reader != null) &#123; try &#123; reader.close(); &#125; catch (XMLStreamException e) &#123; e.printStackTrace(); &#125; &#125; &#125;&#125; 6 对比三种解析方式对比： 特性 DOM SAX StAX 解析模式 树形结构 事件驱动（推模式） 流式处理（拉模式） 内存使用 高（整个文档加载到内存） 低（不需要存储整个文档） 低（不需要存储整个文档） 性能 初始解析慢，但后续访问快 解析快，适合大型文件 解析快，性能接近SAX 访问方式 随机访问 顺序访问（只能向前） 顺序访问（可控制流程） 控制权 应用程序 解析器 应用程序 写入支持 完整支持 只读，写入困难 支持读写 易用性 简单直观 复杂，需要状态管理 中等，比SAX简单 适用场景 小型文档、需要修改 大型文档、只读操作 大型文档、需要控制流程
